toolArgs.file_text:
@page "/catalog"
@using sv_2268d491e30e4ec6a00233b04f366bed.Components.Pages.Catalog
@namespace sv_2268d491e30e4ec6a00233b04f366bed.Components.Pages
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div class="error-message">
        <p>Something went wrong: @_error</p>
        <button @onclick="LoadProducts">Retry</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <CatalogFilters Categories="_categories"
                        OnApplyFilters="HandleApplyFilters"
                        OnClearFilters="HandleClearFilters" />

        <main class="catalog-main">
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_totalCount"
                            Page="_currentPage"
                            PageSize="_pageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (_loading)
            {
                <div class="loading-indicator">
                    <p>Loading products...</p>
                </div>
            }
            else if (_products.Count == 0)
            {
                <div class="empty-results">
                    <p>No products found matching your criteria.</p>
                </div>
            }
            else
            {
                <ProductGrid Products="_products"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />
            }

            @if (_totalPages > 1)
            {
                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </main>
    </div>
}

@code {
    private List<Product> _products = [];
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _pageSize = 12;
    private int _totalCount;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
            await LoadProducts();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task LoadProducts()
    {
        try
        {
            _loading = true;
            _error = null;
            StateHasChanged();

            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);
            _products = result.Items;
            _totalCount = result.TotalCount;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / _pageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleClearFilters()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }
}

